const sel = ($json['Sample query'] || '').toString();
const presets = {
  course: { learnerName: 'Abhiram', learnerEmail: 'abhiram540@gmail.com', orderId: 'CB-10500', queryText: 'Hi, I cannot log into my account and I am unable to access my Python course. It keeps saying invalid credentials. Can you help me get back in?' },
  refund: { learnerName: 'Ravi Kumar', learnerEmail: 'ravi.kumar@example.com', orderId: 'CB-10241', queryText: 'I bought the Power BI course a couple of days ago but it is not what I expected. I would like a refund please.' },
  escalation: { learnerName: 'Arjun Shah', learnerEmail: 'arjun.shah@example.com', orderId: 'CB-11233', queryText: 'My payment failed but the money was deducted from my bank account. I do not see the SQL course in my dashboard. This is a billing problem, please fix it.' }
};
let rec;
if (sel.indexOf('Course access') === 0) rec = presets.course;
else if (sel.indexOf('Refund') === 0) rec = presets.refund;
else if (sel.indexOf('Escalation') === 0) rec = presets.escalation;
else rec = { learnerName: 'Learner', learnerEmail: ($json['Custom learner email'] || 'guest@example.com').toString().trim(), orderId: 'N/A', queryText: ($json['Custom query'] || '').toString().trim() };
return { json: Object.assign({}, rec, { channel: 'web_form' }) };

const orig = $('Build Query').first().json;
let raw = ($json.text || $json.response || '').toString();
const s = raw.indexOf('{');
const e = raw.lastIndexOf('}');
let parsed;
try {
  parsed = JSON.parse(raw.slice(s, e + 1));
} catch (err) {
  parsed = { category: 'other', intent: 'Could not parse classifier output', sentiment: 'neutral', confidence: 0, escalation_reason: null };
}
const allowed = ['course_access', 'refund', 'escalation_human', 'other'];
const category = allowed.includes(parsed.category) ? parsed.category : 'other';
return { json: Object.assign({}, orig, { category: category, intent: parsed.intent || '', sentiment: parsed.sentiment || 'neutral', confidence: parsed.confidence == null ? 0 : parsed.confidence, escalation_reason: parsed.escalation_reason || null }) };

const j = $json;
const daysAgo = (n) => new Date(Date.now() - n * 86400000).toISOString().slice(0, 10);
const accounts = {
  'abhiram540@gmail.com': { learnerName: 'Abhiram', courseName: 'Python for Data Professionals', orderId: 'CB-10500', amountPaid: 3900, purchaseDate: daysAgo(5), paymentStatus: 'success', accountStatus: 'active' },
  'ravi.kumar@example.com': { learnerName: 'Ravi Kumar', courseName: 'Power BI Data Analytics', orderId: 'CB-10241', amountPaid: 4500, purchaseDate: daysAgo(3), paymentStatus: 'success', accountStatus: 'active' },
  'meena.nair@example.com': { learnerName: 'Meena Nair', courseName: 'Python for Data Professionals', orderId: 'CB-10876', amountPaid: 3900, purchaseDate: daysAgo(40), paymentStatus: 'success', accountStatus: 'active' },
  'arjun.shah@example.com': { learnerName: 'Arjun Shah', courseName: 'SQL Beginner to Advanced', orderId: 'CB-11233', amountPaid: 2900, purchaseDate: daysAgo(2), paymentStatus: 'failed_money_deducted', accountStatus: 'payment_pending' }
};
const email = (j.learnerEmail || '').toString().toLowerCase().trim();
const acct = accounts[email] || { learnerName: j.learnerName || 'Learner', courseName: 'Unknown', orderId: j.orderId || 'N/A', amountPaid: 0, purchaseDate: 'N/A', paymentStatus: 'unknown', accountStatus: 'no_account_found' };
let daysSince = null;
let within = false;
if (acct.purchaseDate && acct.purchaseDate !== 'N/A') {
  daysSince = Math.floor((Date.now() - new Date(acct.purchaseDate).getTime()) / 86400000);
  within = daysSince <= 7;
}
return { json: Object.assign({}, j, acct, { learnerName: acct.learnerName, daysSincePurchase: daysSince, withinRefundWindow: within, refundWindowDays: 7 }) };

const j = $json;
j.kbArticle = 'Login / course-access steps: 1) Use the same email you purchased with. 2) Reset your password at codebasics.io/forgot-password. 3) Clear browser cache or try an incognito window. 4) Courses appear under Dashboard > My Learning within a few minutes of payment. If the account shows active and the issue persists after a password reset, our team can manually re-sync access.';
j.kbSource = 'FAQ: Login & Course Access';
return { json: j };

const j = $json;
const within = j.withinRefundWindow === true;
j.refundEligible = within;
j.refundDecision = within ? 'APPROVE_AUTO' : 'DECLINE_OUTSIDE_WINDOW';
j.policyNote = within
  ? 'Purchase is within the 7-day refund window (' + j.daysSincePurchase + ' days ago), so a full refund can be auto-approved and will reach the original payment method in 5-7 business days.'
  : 'Purchase is outside the 7-day refund window (' + j.daysSincePurchase + ' days ago), so a cash refund is not available per policy. We can offer a course swap or learning credit as a goodwill option.';
j.kbSource = 'FAQ: Refund Policy (7-day window)';
return { json: j };

const j = $json;
j.kbArticle = 'General help: Certificates download from Dashboard > My Courses > Download Certificate once 100% completion is reached. For discounts and upcoming sales, the next major sale is announced via email and on codebasics.io, so subscribing to the newsletter ensures you get the code. For course-guidance questions, learners are pointed to the learning-path page based on their goal (data analyst, data scientist, etc.).';
j.kbSource = 'FAQ: General / Certificates / Discounts';
return { json: j };

