const j = $json;
const ticketId = 'TCK-' + Date.now().toString().slice(-6);
const reason = j.escalation_reason || j.intent || 'Needs human review';
const team = 'Tier-2 Human Support';
return { json: {
  learnerName: j.learnerName,
  learnerEmail: j.learnerEmail,
  queryText: j.queryText,
  category: j.category,
  intent: j.intent,
  courseName: j.courseName,
  orderId: j.orderId,
  agentReply: 'Thanks ' + (j.learnerName || 'there') + ', this needs a specialist. I have created ticket ' + ticketId + ' and our human support team will get back to you within 24 hours.',
  status: 'escalated',
  handledBy: 'Human (' + team + ')',
  ticketId: ticketId,
  priority: 'high',
  slaHours: 24,
  internalNote: 'ESCALATION: ' + reason + ' | Learner: ' + j.learnerName + ' <' + j.learnerEmail + '> | Order: ' + j.orderId + ' | Payment: ' + j.paymentStatus,
  timestamp: new Date().toISOString()
} };
